#!/usr/bin/env node
/**
 * build-contracts.mjs — emit .designops/component-contract.json and
 * .designops/theme-contract.json, generated from the code itself so they
 * cannot drift (CI checks reproducibility like every other generated file).
 *
 *   component-contract: one entry per components/ui/<name>/ — import paths,
 *   cva variant/size options (parsed from source), component-token paths,
 *   story/docs coverage, a11y check status.
 *
 *   theme-contract: themes (tokens/theme/*) + modes (tokens/mode/*) with
 *   selectors, status, and override paths.
 *
 * Run: npm run contracts:build
 */
import { readFileSync, readdirSync, writeFileSync, existsSync, statSync } from "node:fs"
import { fileURLToPath } from "node:url"
import { dirname, join } from "node:path"

const root = join(dirname(fileURLToPath(import.meta.url)), "..", "..")
const pkg = JSON.parse(readFileSync(join(root, "package.json"), "utf8"))

/* ---------------- component contract ---------------- */
const TOKEN_NAME = { "radio-group": "radio", sonner: "toast", "navigation-menu": "navigation" }
const pascal = (s) => s.split("-").map((w) => w[0].toUpperCase() + w.slice(1)).join("")

/** Extract top-level keys of an object literal starting at `start` ("{").
 *  Tracks string literals so class-string contents (hover:, dark:, …) are
 *  never mistaken for keys. */
function objectKeys(src, start) {
  const keys = []
  let depth = 0
  let quote = null
  let i = start
  for (; i < src.length; i++) {
    const c = src[i]
    if (quote) {
      if (c === quote && src[i - 1] !== "\\") quote = null
      continue
    }
    // Key check BEFORE string handling so quoted keys ("icon-xs":) are not
    // swallowed as string literals. Value strings never match `"word":`.
    if (depth === 1 && /[\s{,]/.test(src[i - 1] ?? "{")) {
      const m = /^(?:"([\w-]+)"|([\w-]+)):/.exec(src.slice(i, i + 40))
      if (m) {
        keys.push(m[1] ?? m[2])
        i += m[0].length - 1
        continue
      }
    }
    if (c === '"' || c === "'" || c === "`") { quote = c; continue }
    if (c === "{") depth++
    else if (c === "}") { depth--; if (depth === 0) break }
  }
  return { keys, end: i }
}

/** Parse cva variant/size option names from component source. */
function parseCva(src) {
  const out = {}
  const vIdx = src.indexOf("variants:")
  if (vIdx === -1) return out
  const open = src.indexOf("{", vIdx)
  const { keys: groups } = objectKeys(src, open)
  let cursor = open
  for (const group of groups) {
    const gIdx = src.indexOf(`${group}:`, cursor)
    const gOpen = src.indexOf("{", gIdx)
    const { keys, end } = objectKeys(src, gOpen)
    out[group] = keys
    cursor = end
  }
  return out
}

function tokenPaths(node, prefix = "") {
  const out = []
  if (node && typeof node === "object") {
    if ("$value" in node) out.push(prefix)
    else
      for (const [k, v] of Object.entries(node))
        if (!k.startsWith("$")) out.push(...tokenPaths(v, prefix ? `${prefix}.${k}` : k))
  }
  return out
}

const components = {}
const uiDir = join(root, "components", "ui")
for (const d of readdirSync(uiDir, { withFileTypes: true }).filter((d) => d.isDirectory()).sort((a, b) => a.name.localeCompare(b.name))) {
  const name = d.name
  const srcPath = join(uiDir, name, `${name}.tsx`)
  if (!existsSync(srcPath)) continue
  const src = readFileSync(srcPath, "utf8")
  const tokenFile = `${TOKEN_NAME[name] ?? name}.json`
  const tokenFilePath = join(root, "tokens", "component", tokenFile)
  const hasTokens = existsSync(tokenFilePath)
  const hasStories = existsSync(join(root, "stories", "manual", `${name}.stories.tsx`))
  const cva = parseCva(src)
  const entry = {
    status: "stable",
    importPath: `${pkg.name}/${name}`,
    internalPath: `@/components/ui/${name}`,
    source: `components/ui/${name}/${name}.tsx`,
  }
  if (cva.variant?.length) entry.variants = cva.variant
  if (cva.size?.length) entry.sizes = cva.size
  if (hasTokens) {
    const json = JSON.parse(readFileSync(tokenFilePath, "utf8"))
    entry.tokens = tokenPaths(json).sort()
    entry.tokenFile = `tokens/component/${tokenFile}`
  }
  entry.storybook = hasStories ? `stories/manual/${name}.stories.tsx` : null
  entry.docs = existsSync(join(root, "stories", "docs", `${pascal(name)}.mdx`))
    ? `stories/docs/${pascal(name)}.mdx`
    : null
  entry.a11y = hasStories
    ? "axe-checked in CI (test-storybook renders every story with a11y error mode)"
    : "no stories — not axe-checked"
  components[name] = entry
}

writeFileSync(
  join(root, ".designops", "component-contract.json"),
  JSON.stringify(
    {
      package: pkg.name,
      version: pkg.version,
      generated_from: "components/ui/** + tokens/component/** + stories/**",
      note: "GENERATED by scripts/registry/build-contracts.mjs — do not hand-edit; CI checks reproducibility.",
      components,
    },
    null,
    2
  ) + "\n"
)

/* ---------------- theme contract ---------------- */
function overlayInfo(dir, kind) {
  const out = {}
  for (const f of readdirSync(join(root, "tokens", dir)).sort()) {
    if (!f.endsWith(".json")) continue
    const json = JSON.parse(readFileSync(join(root, "tokens", dir, f), "utf8"))
    for (const [name, body] of Object.entries(json[kind] ?? {})) {
      const desc = String(json.$description ?? "")
      out[name] = {
        source: `tokens/${dir}/${f}`,
        status: /PROPOSED/i.test(desc) ? "proposed" : "active",
        extends: typeof body.extends === "string" ? body.extends : undefined,
        overrides: tokenPaths(body).sort(),
      }
      if (out[name].extends === undefined) delete out[name].extends
    }
  }
  return out
}
const themes = overlayInfo("theme", "theme")
const modes = overlayInfo("mode", "mode")
// selectors match scripts/tokens/build-css.mjs
const MODE_SELECTOR = { light: "(base — semantic.css)", dark: ".dark", compact: '[data-density="compact"]', comfortable: '[data-density="comfortable"]', "high-contrast": '[data-contrast="high"]' }
for (const [n, m] of Object.entries(modes)) m.selector = MODE_SELECTOR[n] ?? null
for (const [n, t] of Object.entries(themes)) {
  t.selector = n === "neutral" ? "(base — semantic.css)" : `[data-theme="${n}"]`
  t.css = `dist/themes/${n}.css`
}

writeFileSync(
  join(root, ".designops", "theme-contract.json"),
  JSON.stringify(
    {
      package: pkg.name,
      version: pkg.version,
      generated_from: "tokens/theme/** + tokens/mode/**",
      note: "GENERATED by scripts/registry/build-contracts.mjs — do not hand-edit. Live brand mechanism today: brand.config.json (see docs/theming.md).",
      themes,
      modes,
    },
    null,
    2
  ) + "\n"
)

const stats = Object.values(components)
console.log(
  `.designops/component-contract.json — ${Object.keys(components).length} components ` +
    `(${stats.filter((c) => c.tokens).length} tokenized, ${stats.filter((c) => c.storybook).length} with stories)`
)
console.log(
  `.designops/theme-contract.json — ${Object.keys(themes).length} themes, ${Object.keys(modes).length} modes`
)
